import { Permissao } from './Permissao';
import { DadosUsuario, Usuario } from './Usuario';

export type DadosAdm = DadosUsuario & {
  codigo?: number | null;
  telefone?: string;
  dataNascimento?: string;
};

export class Adm extends Usuario {
  codigo?: number | null;
  telefone?: string;
  dataNascimento?: string;

  constructor(dados: DadosAdm) {
    super({ ...dados, permissao: Permissao.ADM });
    this.codigo = dados.codigo;
    this.telefone = dados.telefone;
    this.dataNascimento = dados.dataNascimento;
  }

  podeGerenciarUsuarios(): boolean {
    return true;
  }

  podeGerenciarMetodosEstudo(): boolean {
    return true;
  }

  podeVisualizarMaterias(): boolean {
    return true;
  }
}
